// Lookup helpers used by the page components
// ---------------------------------------------------------------------------

export function getServiceLocationIntro(
  serviceId: string,
  citySlug: string,
  cityName: string,
): string[] {
  const bespoke = CITY_SERVICE_INTROS[serviceId]?.[citySlug];
  if (bespoke) return bespoke;
  const generic = GENERIC_SERVICE_INTROS[serviceId] || GENERIC_SERVICE_INTROS['electric-swing'];
  return generic(cityName);
}

export function getCityHubIntro(citySlug: string, cityName: string): string[] {
  return CITY_HUB_INTROS[citySlug] || GENERIC_HUB_INTRO(cityName);
}
